#!/usr/bin/perl

use strict;
use warnings;
use URI;
use CGI qw(:standard);

my $cgi = CGI->new;
my $next = $cgi->param('next') || '';

# Validate redirect URL
my $redirect_url = '';
if ($next && is_valid_redirect($next)) {
    $redirect_url = $next;
} else {
    # Default redirect if invalid or missing
    $redirect_url = '/';
}

print "Location: $redirect_url\n\n";

sub is_valid_redirect {
    my $url = shift;
    
    # Parse the URL
    my $uri = URI->new($url);
    
    # Check if it's a relative URL
    if (!$uri->scheme && !$uri->host) {
        return 1;
    }
    
    # Check if it's an absolute URL with same domain
    my $current_host = $cgi->server_name();
    if ($uri->host && $uri->host eq $current_host) {
        return 1;
    }
    
    # Allow only specific domains if needed
    my @allowed_domains = ('example.com', 'www.example.com');
    foreach my $domain (@allowed_domains) {
        if ($uri->host && $uri->host eq $domain) {
            return 1;
        }
    }
    
    return 0;
}